                'nutriscore_score' => isset($p['nutriscore_score']) ? (int)$p['nutriscore_score'] : null,
                'ecoscore_grade' => strtoupper($p['ecoscore_grade'] ?? '') ?: null,
                'ecoscore_score' => isset($p['ecoscore_score']) ? (int)$p['ecoscore_score'] : null,
